SAMPLE_CODE(TestMyTypefaceCodeSnippet, "Iosevka Carrot Mono", DARK) { // The qucik brown fox jumps over the lazy dog.
    const wchar_t* code = L"(<#part>\\d+)(<#captrue>(<section>(<&part>)))((<&capture>).){3}(<&capture>)";
    RegexNode node = (rCapture(L"section", r_d().Some()) + rC(L'.')).Loop(3, 3) + rCapture(L"section", r_d().Some());
    ThePatternMustBeSame(code, node); // Clarity : [i l I 1] [0 O 8] 1234567890. {}[]()<>$*-+=/#_%^@\&|~?'"`!,.;:
}
